import React, { useState, useEffect, useRef, useCallback } from 'react';
import { createRoot } from 'react-dom/client';
import { 
  GoogleGenAI, 
  LiveServerMessage, 
  Modality, 
  Blob 
} from '@google/genai';
import { 
  Mic, 
  MicOff, 
  Camera, 
  CameraOff, 
  BookOpen, 
  MessageSquare, 
  Sparkles, 
  History, 
  StopCircle,
  Play,
  Zap,
  ChevronRight,
  Maximize2
} from 'lucide-react';

// --- Constants ---
const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-12-2025';
const AUDIO_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;
const FRAME_RATE = 1; // 1 frame per second for slides
const JPEG_QUALITY = 0.6;

// --- Helper Functions ---
function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function blobToBase64(blob: globalThis.Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = (reader.result as string).split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

// --- App Component ---
const App: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [transcriptions, setTranscriptions] = useState<{ role: 'user' | 'model', text: string }[]>([]);
  const [insights, setInsights] = useState<{ id: string, title: string, content: string, type: 'term' | 'summary' | 'action' }[]>([]);
  const [status, setStatus] = useState<string>('Ready to listen');

  const aiRef = useRef<GoogleGenAI | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const audioContextsRef = useRef<{ input: AudioContext; output: AudioContext } | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const frameIntervalRef = useRef<number | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);
  const currentTranscriptionRef = useRef({ user: '', model: '' });

  useEffect(() => {
    aiRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    return () => {
      stopSession();
    };
  }, []);

  const startSession = async () => {
    if (!aiRef.current) return;

    try {
      setStatus('Initializing hardware...');
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_SAMPLE_RATE });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
      audioContextsRef.current = { input: inputCtx, output: outputCtx };

      setStatus('Connecting to AI...');
      const sessionPromise = aiRef.current.live.connect({
        model: MODEL_NAME,
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setStatus('Live: Listening to lecture');

            // Start streaming audio
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob: Blob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            // Handle Audio
            const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && audioContextsRef.current) {
              const { output } = audioContextsRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
              const buffer = await decodeAudioData(decode(audioData), output, OUTPUT_SAMPLE_RATE, 1);
              const source = output.createBufferSource();
              source.buffer = buffer;
              source.connect(output.destination);
              source.addEventListener('ended', () => sourcesRef.current.delete(source));
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (msg.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }

            // Handle Transcriptions
            if (msg.serverContent?.inputAudioTranscription) {
              currentTranscriptionRef.current.user += msg.serverContent.inputAudioTranscription.text;
            }
            if (msg.serverContent?.outputAudioTranscription) {
              currentTranscriptionRef.current.model += msg.serverContent.outputAudioTranscription.text;
            }

            if (msg.serverContent?.turnComplete) {
              const userText = currentTranscriptionRef.current.user.trim();
              const modelText = currentTranscriptionRef.current.model.trim();

              if (userText) setTranscriptions(prev => [...prev, { role: 'user', text: userText }]);
              if (modelText) setTranscriptions(prev => [...prev, { role: 'model', text: modelText }]);

              // Trigger automated insight extraction based on the latest turn
              if (modelText.length > 20) {
                // This is a simplified logic. In a real app, you might use a separate tool call.
                // Here we'll simulate an insight if specific keywords or length are met.
              }

              currentTranscriptionRef.current = { user: '', model: '' };
            }
          },
          onerror: (e) => {
            console.error(e);
            setStatus('Connection error');
            stopSession();
          },
          onclose: () => {
            setIsActive(false);
            setStatus('Session ended');
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          systemInstruction: `You are a high-performance Lecture Assistant. Your goal is to help students by:
          1. Transcribing the lecture clearly.
          2. Identifying and explaining complex terms.
          3. Summarizing key points as the lecture progresses.
          4. Answering questions about the current content or visuals provided via camera.
          Be concise, scholarly yet accessible, and helpful.`,
        }
      });
      sessionPromiseRef.current = sessionPromise;
    } catch (err) {
      console.error(err);
      setStatus('Hardware access denied');
    }
  };

  const stopSession = () => {
    sessionPromiseRef.current?.then(s => s.close());
    streamRef.current?.getTracks().forEach(t => t.stop());
    if (frameIntervalRef.current) clearInterval(frameIntervalRef.current);
    setIsActive(false);
    setIsCameraActive(false);
    setStatus('Ready');
  };

  const toggleCamera = async () => {
    if (!isCameraActive) {
      try {
        const videoStream = await navigator.mediaDevices.getUserMedia({ video: true });
        if (videoRef.current) {
          videoRef.current.srcObject = videoStream;
          setIsCameraActive(true);

          // Start frame capture
          frameIntervalRef.current = window.setInterval(() => {
            if (videoRef.current && canvasRef.current && isActive && sessionPromiseRef.current) {
              const ctx = canvasRef.current.getContext('2d');
              canvasRef.current.width = videoRef.current.videoWidth;
              canvasRef.current.height = videoRef.current.videoHeight;
              ctx?.drawImage(videoRef.current, 0, 0);
              canvasRef.current.toBlob(async (blob) => {
                if (blob) {
                  const data = await blobToBase64(blob);
                  sessionPromiseRef.current?.then(s => s.sendRealtimeInput({ media: { data, mimeType: 'image/jpeg' } }));
                }
              }, 'image/jpeg', JPEG_QUALITY);
            }
          }, 1000 / FRAME_RATE);
        }
      } catch (err) {
        console.error("Camera access failed", err);
      }
    } else {
      if (videoRef.current?.srcObject) {
        (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
      }
      if (frameIntervalRef.current) clearInterval(frameIntervalRef.current);
      setIsCameraActive(false);
    }
  };

  const addInsight = (type: 'term' | 'summary' | 'action', title: string, content: string) => {
    setInsights(prev => [{ id: Date.now().toString(), type, title, content }, ...prev]);
  };

  // Auto-scroll transcription
  const transcriptEndRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [transcriptions]);

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans flex flex-col">
      {/* Header */}
      <header className="h-16 bg-white border-b border-slate-200 px-6 flex items-center justify-between sticky top-0 z-10 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
            <BookOpen size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800 leading-none">Lumen</h1>
            <p className="text-xs font-medium text-slate-400 mt-1 uppercase tracking-wider">AI Lecture Companion</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 bg-slate-100 px-3 py-1.5 rounded-full border border-slate-200">
            <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`} />
            <span className="text-sm font-semibold text-slate-600">{status}</span>
          </div>
          <button 
            onClick={isActive ? stopSession : startSession}
            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-bold transition-all active:scale-95 shadow-lg shadow-indigo-100 ${
              isActive 
                ? 'bg-rose-50 text-rose-600 hover:bg-rose-100 border border-rose-200' 
                : 'bg-indigo-600 text-white hover:bg-indigo-700'
            }`}
          >
            {isActive ? <StopCircle size={20} /> : <Play size={20} />}
            {isActive ? 'Stop' : 'Start Assistant'}
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden p-6 gap-6 max-w-[1600px] mx-auto w-full">
        {/* Left: Video & Insights */}
        <div className="w-1/3 flex flex-col gap-6 overflow-hidden">
          {/* Slide View (Camera) */}
          <div className="bg-slate-900 rounded-3xl overflow-hidden aspect-video relative group shadow-2xl border border-slate-800">
            {isCameraActive ? (
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                muted 
                className="w-full h-full object-cover"
              />
            ) : (
              <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500 gap-4 bg-slate-950">
                <div className="w-16 h-16 rounded-full bg-slate-900 flex items-center justify-center border border-slate-800 group-hover:scale-110 transition-transform">
                  <Camera size={32} />
                </div>
                <p className="text-sm font-medium">Slide Capture Disabled</p>
              </div>
            )}

            <button 
              onClick={toggleCamera}
              className={`absolute bottom-4 right-4 p-3 rounded-2xl transition-all shadow-xl backdrop-blur-md ${
                isCameraActive 
                ? 'bg-rose-500/90 text-white hover:bg-rose-600' 
                : 'bg-white/90 text-slate-900 hover:bg-white'
              }`}
            >
              {isCameraActive ? <CameraOff size={20} /> : <Camera size={20} />}
            </button>

            {isActive && (
              <div className="absolute top-4 left-4 flex items-center gap-2 px-3 py-1.5 rounded-full bg-black/40 backdrop-blur-md border border-white/10">
                <Zap size={14} className="text-amber-400 fill-amber-400" />
                <span className="text-xs font-bold text-white uppercase tracking-widest">Live Analysis</span>
              </div>
            )}
          </div>

          {/* Insights Panel */}
          <div className="flex-1 bg-white rounded-3xl border border-slate-200 overflow-hidden flex flex-col shadow-sm">
            <div className="p-5 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div className="flex items-center gap-2">
                <Sparkles size={18} className="text-indigo-600" />
                <h2 className="font-bold text-slate-800">Live Insights</h2>
              </div>
              <span className="text-[10px] font-bold px-2 py-0.5 bg-indigo-100 text-indigo-700 rounded-full uppercase tracking-tighter">AI Powered</span>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {insights.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-50 space-y-2 py-10">
                  <History size={40} strokeWidth={1.5} />
                  <p className="text-sm font-medium text-center px-8">Analysis cards will appear here as the lecture continues.</p>
                </div>
              ) : (
                insights.map((insight) => (
                  <div key={insight.id} className="group p-4 bg-slate-50 rounded-2xl border border-slate-100 hover:border-indigo-200 hover:bg-white transition-all shadow-sm hover:shadow-md">
                    <div className="flex items-center gap-2 mb-2">
                      <span className={`text-[10px] font-black uppercase px-2 py-0.5 rounded-md ${
                        insight.type === 'term' ? 'bg-amber-100 text-amber-700' :
                        insight.type === 'summary' ? 'bg-indigo-100 text-indigo-700' :
                        'bg-emerald-100 text-emerald-700'
                      }`}>
                        {insight.type}
                      </span>
                      <h3 className="text-sm font-bold text-slate-800 flex-1 truncate">{insight.title}</h3>
                    </div>
                    <p className="text-sm text-slate-600 leading-relaxed line-clamp-3 group-hover:line-clamp-none transition-all">
                      {insight.content}
                    </p>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

        {/* Right: Transcription Feed */}
        <div className="flex-1 flex flex-col bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm relative">
          <div className="p-5 border-b border-slate-100 flex items-center justify-between sticky top-0 bg-white/80 backdrop-blur-md z-10">
            <div className="flex items-center gap-2">
              <MessageSquare size={18} className="text-indigo-600" />
              <h2 className="font-bold text-slate-800">Transcript</h2>
            </div>
            <div className="flex items-center gap-3">
              <button className="text-slate-400 hover:text-indigo-600 transition-colors p-1.5 hover:bg-slate-100 rounded-lg">
                <Maximize2 size={18} />
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth">
            {transcriptions.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center space-y-4 opacity-30">
                <Mic size={48} />
                <div className="text-center space-y-1">
                  <p className="text-xl font-bold">Transcription Feed</p>
                  <p className="text-sm font-medium">Start the session to see live conversation</p>
                </div>
              </div>
            ) : (
              transcriptions.map((t, idx) => (
                <div key={idx} className={`flex gap-4 group animate-in slide-in-from-bottom-2 duration-300 ${t.role === 'user' ? '' : 'flex-row-reverse'}`}>
                  <div className={`w-8 h-8 rounded-full shrink-0 flex items-center justify-center text-xs font-bold border ${
                    t.role === 'user' 
                    ? 'bg-white text-slate-400 border-slate-200' 
                    : 'bg-indigo-600 text-white border-indigo-500 shadow-md shadow-indigo-100'
                  }`}>
                    {t.role === 'user' ? 'LEC' : 'LU'}
                  </div>
                  <div className={`max-w-[85%] space-y-1 ${t.role === 'model' ? 'text-right' : ''}`}>
                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">
                      {t.role === 'user' ? 'Lecturer / Environment' : 'Lumen Assistant'}
                    </div>
                    <div className={`p-4 text-sm leading-relaxed ${
                      t.role === 'user' 
                      ? 'bg-slate-50 text-slate-800 rounded-2xl rounded-tl-none' 
                      : 'bg-indigo-50 text-indigo-900 rounded-2xl rounded-tr-none'
                    }`}>
                      {t.text}
                    </div>
                  </div>
                </div>
              ))
            )}
            <div ref={transcriptEndRef} />
          </div>

          {/* Bottom Bar / Quick Controls */}
          <div className="p-4 border-t border-slate-100 bg-slate-50/50 flex items-center justify-center gap-6">
            <div className="flex items-center gap-6 text-slate-400">
              <button 
                onClick={() => addInsight('term', 'New Concept', 'AI is extracting a definition from the latest lecture snippet...')}
                className="flex items-center gap-2 text-[10px] font-black uppercase hover:text-indigo-600 transition-colors"
              >
                <ChevronRight size={14} /> Capture Term
              </button>
              <div className="w-px h-4 bg-slate-200" />
              <button 
                onClick={() => addInsight('summary', 'Session Recap', 'Summarizing the key takeaway from the current topic.')}
                className="flex items-center gap-2 text-[10px] font-black uppercase hover:text-indigo-600 transition-colors"
              >
                <Sparkles size={14} /> Create Summary
              </button>
            </div>
          </div>
        </div>
      </main>

      <canvas ref={canvasRef} className="hidden" />

      {/* Floating Listening Indicator */}
      {isActive && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-20 flex items-center gap-4 bg-slate-900/90 backdrop-blur-xl px-6 py-4 rounded-3xl border border-white/10 shadow-2xl animate-in fade-in zoom-in slide-in-from-bottom-10">
          <div className="flex gap-1 items-center h-4">
            {[1, 2, 3, 4, 5].map((i) => (
              <div 
                key={i} 
                className="w-1.5 bg-indigo-400 rounded-full animate-bounce" 
                style={{ height: `${Math.random() * 100}%`, animationDelay: `${i * 0.1}s` }}
              />
            ))}
          </div>
          <span className="text-white text-xs font-black uppercase tracking-widest pr-4">Lumen is Active</span>
          <div className="h-6 w-px bg-white/10 mx-2" />
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-xl bg-white/5 border border-white/10 ${isCameraActive ? 'text-indigo-400' : 'text-white/40'}`}>
              <Camera size={16} />
            </div>
            <div className="p-2 rounded-xl bg-white/5 border border-white/10 text-indigo-400">
              <Mic size={16} />
            </div>
          </div>
        </div>
      )}

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes bounce {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-5px); }
        }
        .animate-bounce {
          animation: bounce 0.6s infinite ease-in-out;
        }
        body {
          overscroll-behavior: none;
        }
        ::-webkit-scrollbar {
          width: 6px;
        }
        ::-webkit-scrollbar-track {
          background: transparent;
        }
        ::-webkit-scrollbar-thumb {
          background: #e2e8f0;
          border-radius: 10px;
        }
        ::-webkit-scrollbar-thumb:hover {
          background: #cbd5e1;
        }
      `}} />
    </div>
  );
};

// Render App
const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<App />);
}
